using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using Confirmit.CATI.Common.ServiceLocation;
using Confirmit.CATI.Core.DAL.Generated.Entity.Adapter;
using Confirmit.CATI.Core.DAL.Generated.Entity.Table;
using Confirmit.CATI.Core.Repositories.Interfaces;
using Confirmit.CATI.Core.Services.RecordsMigration;
using Confirmit.CATI.Monitoring.Common;
using Confirmit.CATI.Monitoring.Common.Contracts;
using Confirmit.CATI.Monitoring.Common.StateData;
using Ionic.Zlib;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Newtonsoft.Json;

namespace Confirmit.CATI.IntegrationTests.Tests.RoutineMaintenance.Actions
{
    [TestClass]
    public class SavedRecordsMigrationActionsTest : BaseMockedIntegrationTest
    {
        private MigrationService _migrationService;

        private const string BinaryFormatterEventsFile = "";
        private const string BinaryFormatterEventsFileEx = "";
        private const string JsonEventsFile = "";
        private const string FailedEventsFile = "ED594913EC366EFE2FEFAA99D7DA1757CD417B4BA123123123";
        
        public override void OnPostTestInitialize()
        {
            _migrationService = new MigrationService(ServiceLocator.Resolve<IDeferredMonitoringRepository>());
        }

        [TestMethod, Owner(@"firm\GrigoryK")]
        public void MigrateDeferredRecords_TwoBFSavedRecordsTwoJsonSavedRecordsOneJsonRecord_AllNeededRecordsMigrated()
        {
            AddDeferredRecord(JsonEventsFile, true);
            AddDeferredRecord(JsonEventsFile, true);
            AddDeferredRecord(JsonEventsFile, false);
            AddDeferredRecord(BinaryFormatterEventsFile, true);
            AddDeferredRecord(BinaryFormatterEventsFileEx, true);
            
            var result = _migrationService.MigrateDeferredRecords();
            
            Assert.AreEqual(4, result.totalRecordsCount);
            Assert.AreEqual(2, result.migratedRecordsCount);
            Assert.AreEqual(0, result.failedRecordsCount);
            Assert.AreEqual(2, result.alreadyMigratedRecordsCount);

            CheckAllRecordsAreJsonSerialized(5);
        }

        [TestMethod, Owner(@"firm\GrigoryK")]
        public void MigrateDeferredRecords_TwoFailedRecordsOneSavedRecord_NothingWereMigrated()
        {
            AddDeferredRecord(FailedEventsFile, true);
            AddDeferredRecord(FailedEventsFile, false);
            AddDeferredRecord(JsonEventsFile, true);
            AddDeferredRecord(BinaryFormatterEventsFile, true);
            
            var result = _migrationService.MigrateDeferredRecords();
            
            Assert.AreEqual(3, result.totalRecordsCount);
            Assert.AreEqual(1, result.migratedRecordsCount);
            Assert.AreEqual(1, result.failedRecordsCount);
            Assert.AreEqual(1, result.alreadyMigratedRecordsCount);
        }

        private void CheckAllRecordsAreJsonSerialized(int cnt)
        {
            var records = BvPersonDeferredMonitoringAdapter.GetAll();
            Assert.AreEqual(cnt, records.Count);
            
            foreach (var record in records)
            {
                Assert.IsTrue(IsJsonSerializedData(record.EventsFile));
            }
        }

        private static readonly JsonSerializerSettings JsonSettings = new JsonSerializerSettings
        {
            TypeNameHandling = TypeNameHandling.Auto,
            TypeNameAssemblyFormatHandling = TypeNameAssemblyFormatHandling.Simple,
            SerializationBinder = new EventStateDeserializationBinder()
        };
        
        private bool IsJsonSerializedData(byte[] eventsFile)
        {
            using (var source = new MemoryStream(eventsFile))
            using (var ds = new DeflateStream(source, CompressionMode.Decompress, leaveOpen: true))
            using (var ms = new MemoryStream())
            {
                ds.CopyTo(ms);

                var jsonBytes = ms.ToArray();

                string json = Encoding.UTF8.GetString(jsonBytes);

                // Try to deserialize as collection
                try
                {
                    var collection = JsonConvert.DeserializeObject<List<StateEventInfo>>(json, JsonSettings);
                    foreach (var deserialized in collection)
                    {
                        DeserializeStateByJson(deserialized.MessageType, deserialized.State);
                    }
                    
                    return true;
                }
                catch
                {
                }
                
                // Try to deserialize as single object
                try
                {
                    var deserialized = JsonConvert.DeserializeObject<StateEventInfo>(json, JsonSettings);
                    DeserializeStateByJson(deserialized.MessageType, deserialized.State);
                    return true;
                }
                catch
                {
                }

                return false;
            }
        }

        private static void DeserializeStateByJson(MonitoringMessageTypes type, byte[] binary)
        {
            byte[] jsonBytes = binary;

            if (type == MonitoringMessageTypes.MonitoringInitialMessage ||
                type == MonitoringMessageTypes.InterviewInitialMessage ||
                type == MonitoringMessageTypes.InterviewPageBrowserPageCompletedMessage)
            {
                using (var input = new MemoryStream(binary))
                using (var deflate = new DeflateStream(input, CompressionMode.Decompress))
                using (var output = new MemoryStream())
                {
                    deflate.CopyTo(output);
                    jsonBytes = output.ToArray();
                }
            }

            string json = Encoding.UTF8.GetString(jsonBytes);
            JsonConvert.DeserializeObject<BaseStateData>(json, JsonSettings);
        }
        
        private byte[] ConvertHexStringToByte(string hex)
        {
            return Enumerable.Range(0, hex.Length / 2)
                .Select(i => Convert.ToByte(hex.Substring(i * 2, 2), 16))
                .ToArray();
        }

        private void AddDeferredRecord(string eventsFile, bool isSaved)
        {
            var entity = new BvPersonDeferredMonitoringEntity
            {
                EventsFile = ConvertHexStringToByte(eventsFile),
                IsRetained = isSaved,
                ClientTimeUtc = DateTime.UtcNow,
                RecordCreationTime = DateTime.UtcNow,
                ServerTimeUtc = DateTime.UtcNow,
                TimeStamp = DateTime.UtcNow
            };

            AddDeferredRecord(entity);
        }
        
        private void AddDeferredRecord(BvPersonDeferredMonitoringEntity entity)
        {
            BvPersonDeferredMonitoringAdapter.Insert(entity);
        }
    }
}
